# Skeptic: only packet-taught patterns; explicit I/O contract
def assess(record: dict) -> str:
    required = {'event_time', 'window_end', 'case_id', 'allowed_lateness', 'watermark'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    if record.get('event_time') not in (None, False, 0, "", set(), [], {}):
        return 'PASS'
    return 'REJECT'

valid = {"case_id": 'CASO-SYN-1A', 'event_time': True, 'window_end': True, 'watermark': True, 'allowed_lateness': True}
adverse = {"case_id": 'CASO-SYN-1A-ADV', 'event_time': False, 'window_end': False, 'watermark': False, 'allowed_lateness': False}
missing = {k: valid[k] for k in valid if k != 'allowed_lateness'}
print(assess(valid))
print(assess(adverse))
print(assess(missing))

