# Skeptic: only packet-taught patterns; explicit I/O contract
def assess(record: dict) -> str:
    required = {"case_id", "nodes", "edges", "typed_io"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if not (not record["typed_io"] or any(a == b for a,b in record["edges"])) else "REJECT_DAG"

valid = {"case_id": "CASO-HYO-046-2A", **{"nodes":{"raw","clean","report"},"edges":{("raw","clean"),("clean","report")},"typed_io":True}}
invalid = {"case_id": "CASO-HYO-046-2A", **{"nodes":{"raw","clean"},"edges":{("raw","raw"),("clean","report")},"typed_io":False}}
incomplete = {**valid}
incomplete.pop("typed_io")
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)
print(assess(valid))
missing = {k: valid[k] for k in valid if k != 'typed_io'}
print(assess(missing))

